external_knowledge:
; An artist's popularity can be determined by their track's access counts and popularity scores; 
; The number of followers an artist has is related to their popularity; 
; The top 5 artists refer to the artists with the highest total access counts and average popularity scores.

sql:
SELECT COUNT(track_id) AS track_count
FROM playlists_tracks
WHERE playlist_id = '0';

SELECT artist_id, SUM(followers) AS total_followers
FROM artists
GROUP BY artist_id;

external_knowledge:
; This question implies knowledge of what 'top three most played tracks' means, which is based on the count of access events for each track; 
; The tracks are ranked per artist based on play counts in descending order; 
; An artist may have multiple tracks, but only their top three most played are of interest.

sql:
SELECT followers
FROM artists
WHERE artist_id = '0';
